import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as l,d}from"./app-b2b64365.js";const _={},r=d('<p>据说，Python 的对象天生拥有一些神奇的方法，它们总被双下划线所包围，他们是面向对象的 Python 的一切。</p><p>他们是可以给你的类增加魔力的特殊方法，如果你的对象实现（重载）了这些方法中的某一个，那么这个方法就会在特殊的情况下被 Python 所调用，你可以定义自己想要的行为，而这一切都是自动发生的。</p><p>Python 的魔术方法非常强大，然而随之而来的则是责任。了解正确的方法去使用非常重要！</p><h2 id="基本的魔法方法" tabindex="-1"><a class="header-anchor" href="#基本的魔法方法" aria-hidden="true">#</a> 基本的魔法方法</h2><table><thead><tr><th>魔法方法</th><th>含义</th></tr></thead><tbody><tr><td><code>__new__(cls[, ...])</code></td><td>1、new 是在一个对象实例化的时候所调用的第一个方法<br>2、它的第一个参数是这个类，其他的参数是用来直接传递给 init 方法<br>3、new 决定是否要使用该 init 方法，因为 new 可以调用其他类的构造方法或者直接返回别的实例对象来作为本类的实例，如果 new 没有返回实例对象，则 init 不会被调用<br>4、new 主要是用于继承一个不可变的类型比如一个 tuple 或者 string</td></tr><tr><td><code>__init__(self[, ...])</code></td><td>构造器，当一个实例被创建的时候调用的初始化方法</td></tr><tr><td><code>__del__(self) ​</code></td><td>析构器，当一个实例被销毁的时候调用的方法</td></tr><tr><td><code>__call__(self[, args...])</code></td><td>允许一个类的实例像函数一样被调用：x(a, b) 调用 x.<strong>call</strong>(a, b)</td></tr><tr><td><code>__len__(self)</code></td><td>定义当被 len() 调用时的行为</td></tr><tr><td><code>__repr__(self)</code></td><td>定义当被 repr() 调用时的行为</td></tr><tr><td><code>__str__(self)</code></td><td>定义当被 str() 调用时的行为 类似于Java中toString方法</td></tr><tr><td><code>__bytes__(self)</code></td><td>定义当被 bytes() 调用时的行为</td></tr><tr><td><code>__hash__(self)</code></td><td>定义当被 hash() 调用时的行为</td></tr><tr><td><code>__bool__(self)</code></td><td>定义当被 bool() 调用时的行为，应该返回 True 或 False</td></tr><tr><td><code>__format__(self, format_spec)</code></td><td>定义当被 format() 调用时的行为</td></tr></tbody></table><h2 id="有关属性" tabindex="-1"><a class="header-anchor" href="#有关属性" aria-hidden="true">#</a> 有关属性</h2><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__getattr__(self, name)</code></td><td style="text-align:left;">定义当用户试图获取一个不存在的属性时的行为</td></tr><tr><td style="text-align:left;"><code>__getattribute__(self, name)</code></td><td style="text-align:left;">定义当该类的属性被访问时的行为</td></tr><tr><td style="text-align:left;"><code>__setattr__(self, name, value)</code></td><td style="text-align:left;">定义当一个属性被设置时的行为</td></tr><tr><td style="text-align:left;"><code>__delattr__(self, name)</code></td><td style="text-align:left;">定义当一个属性被删除时的行为</td></tr><tr><td style="text-align:left;"><code>__dir__(self)</code></td><td style="text-align:left;">定义当 dir() 被调用时的行为</td></tr><tr><td style="text-align:left;"><code>__get__(self, instance, owner)</code></td><td style="text-align:left;">定义当描述符的值被取得时的行为</td></tr><tr><td style="text-align:left;"><code>__set__(self, instance, value)</code></td><td style="text-align:left;">定义当描述符的值被改变时的行为</td></tr><tr><td style="text-align:left;"><code>__delete__(self, instance)</code></td><td style="text-align:left;">定义当描述符的值被删除时的行为</td></tr></tbody></table><h2 id="比较操作符" tabindex="-1"><a class="header-anchor" href="#比较操作符" aria-hidden="true">#</a> 比较操作符</h2><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__lt__(self, other)</code></td><td style="text-align:left;">定义小于号的行为：x &lt; y 调用 <code>x.__lt__(y)</code></td></tr><tr><td style="text-align:left;"><code>__le__(self, other)</code></td><td style="text-align:left;">定义小于等于号的行为：x &lt;= y 调用 <code>x.__le__(y)</code></td></tr><tr><td style="text-align:left;"><code>__eq__(self, other)</code></td><td style="text-align:left;">定义等于号的行为：x == y 调用 <code>x.__eq__(y)</code></td></tr><tr><td style="text-align:left;"><code>__ne__(self, other)</code></td><td style="text-align:left;">定义不等号的行为：x != y 调用 <code>x.__ne__(y)</code></td></tr><tr><td style="text-align:left;"><code>__gt__(self, other)</code></td><td style="text-align:left;">定义大于号的行为：x &gt; y 调用 <code>x.__gt__(y)</code></td></tr><tr><td style="text-align:left;"><code>__ge__(self, other)</code></td><td style="text-align:left;">定义大于等于号的行为：x &gt;= y 调用 <code>x.__ge__(y)</code></td></tr></tbody></table><h2 id="算数运算符" tabindex="-1"><a class="header-anchor" href="#算数运算符" aria-hidden="true">#</a> 算数运算符</h2><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__add__(self, other)</code></td><td style="text-align:left;">定义加法的行为：+</td></tr><tr><td style="text-align:left;"><code>__sub__(self, other)</code></td><td style="text-align:left;">定义减法的行为：-</td></tr><tr><td style="text-align:left;"><code>__mul__(self, other)</code></td><td style="text-align:left;">定义乘法的行为：*</td></tr><tr><td style="text-align:left;"><code>__truediv__(self, other)</code></td><td style="text-align:left;">定义真除法的行为：/</td></tr><tr><td style="text-align:left;"><code>__floordiv__(self, other)</code></td><td style="text-align:left;">定义整数除法的行为：//</td></tr><tr><td style="text-align:left;"><code>__mod__(self, other)</code></td><td style="text-align:left;">定义取模算法的行为：%</td></tr><tr><td style="text-align:left;"><code>__divmod__(self, other)</code></td><td style="text-align:left;">定义当被 divmod() 调用时的行为</td></tr><tr><td style="text-align:left;"><code>__pow__(self, other[, modulo])</code></td><td style="text-align:left;">定义当被 power() 调用或 运算时的行为</td></tr><tr><td style="text-align:left;"><code>__lshift__(self, other)</code></td><td style="text-align:left;">定义按位左移位的行为：&lt;&lt;</td></tr><tr><td style="text-align:left;"><code>__rshift__(self, other)</code></td><td style="text-align:left;">定义按位右移位的行为：&gt;&gt;</td></tr><tr><td style="text-align:left;"><code>__and__(self, other)</code></td><td style="text-align:left;">定义按位与操作的行为：&amp;</td></tr><tr><td style="text-align:left;"><code>__xor__(self, other)</code></td><td style="text-align:left;">定义按位异或操作的行为：^</td></tr><tr><td style="text-align:left;"><code>__or__(self, other)</code></td><td style="text-align:left;">定义按位或操作的行为：`</td></tr></tbody></table><h2 id="反运算" tabindex="-1"><a class="header-anchor" href="#反运算" aria-hidden="true">#</a> 反运算</h2><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__radd__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rsub__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rmul__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rtruediv__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rfloordiv__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rmod__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rdivmod__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rpow__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rlshift__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rrshift__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__rxor__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr><tr><td style="text-align:left;"><code>__ror__(self, other)</code></td><td style="text-align:left;">（与上方相同，当左操作数不支持相应的操作时被调用）</td></tr></tbody></table><h2 id="增量赋值运算" tabindex="-1"><a class="header-anchor" href="#增量赋值运算" aria-hidden="true">#</a> 增量赋值运算</h2><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__iadd__(self, other)</code></td><td style="text-align:left;">定义赋值加法的行为：+=</td></tr><tr><td style="text-align:left;"><code>__isub__(self, other)</code></td><td style="text-align:left;">定义赋值减法的行为：-=</td></tr><tr><td style="text-align:left;"><code>__imul__(self, other)</code></td><td style="text-align:left;">定义赋值乘法的行为：<code>*=</code></td></tr><tr><td style="text-align:left;"><code>__itruediv__(self, other)</code></td><td style="text-align:left;">定义赋值真除法的行为：<code>/=</code></td></tr><tr><td style="text-align:left;"><code>__ifloordiv__(self, other)</code></td><td style="text-align:left;">定义赋值整数除法的行为：//=</td></tr><tr><td style="text-align:left;"><code>__imod__(self, other)</code></td><td style="text-align:left;">定义赋值取模算法的行为：%=</td></tr><tr><td style="text-align:left;"><code>__ipow__(self, other[, modulo])</code></td><td style="text-align:left;">定义赋值幂运算的行为：<code>**=</code></td></tr><tr><td style="text-align:left;"><code>__ilshift__(self, other)</code></td><td style="text-align:left;">定义赋值按位左移位的行为：&lt;&lt;=</td></tr><tr><td style="text-align:left;"><code>__irshift__(self, other)</code></td><td style="text-align:left;">定义赋值按位右移位的行为：&gt;&gt;=</td></tr><tr><td style="text-align:left;"><code>__iand__(self, other)</code></td><td style="text-align:left;">定义赋值按位与操作的行为：&amp;=</td></tr><tr><td style="text-align:left;"><code>__ixor__(self, other)</code></td><td style="text-align:left;">定义赋值按位异或操作的行为：^=</td></tr><tr><td style="text-align:left;"><code>__ior__(self, other)</code></td><td style="text-align:left;">定义赋值按位或操作的行为：`</td></tr></tbody></table><h2 id="一元操作符" tabindex="-1"><a class="header-anchor" href="#一元操作符" aria-hidden="true">#</a> 一元操作符</h2><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__neg__(self)</code></td><td style="text-align:left;">定义正号的行为：+x</td></tr><tr><td style="text-align:left;"><code>__pos__(self)</code></td><td style="text-align:left;">定义负号的行为：-x</td></tr><tr><td style="text-align:left;"><code>__abs__(self)</code></td><td style="text-align:left;">定义当被 abs() 调用时的行为</td></tr><tr><td style="text-align:left;"><code>__invert__(self)</code></td><td style="text-align:left;">定义按位求反的行为：~x</td></tr></tbody></table><p>类型转换</p><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__complex__(self)</code></td><td style="text-align:left;">定义当被 complex() 调用时的行为（需要返回恰当的值）</td></tr><tr><td style="text-align:left;"><code>__int__(self)</code></td><td style="text-align:left;">定义当被 int() 调用时的行为（需要返回恰当的值）</td></tr><tr><td style="text-align:left;"><code>__float__(self)</code></td><td style="text-align:left;">定义当被 float() 调用时的行为（需要返回恰当的值）</td></tr><tr><td style="text-align:left;"><code>__round__(self[, n])</code></td><td style="text-align:left;">定义当被 round() 调用时的行为（需要返回恰当的值）</td></tr><tr><td style="text-align:left;"><code>__index__(self)</code></td><td style="text-align:left;">当对象是被应用在切片表达式中时，实现整形强制转换<br>如果你定义了一个可能在切片时用到的定制的数值型,你应该定义 index<br>如果 index 被定义，则 int 也需要被定义，且返回相同的值</td></tr></tbody></table><h2 id="上下文管理-with-语句" tabindex="-1"><a class="header-anchor" href="#上下文管理-with-语句" aria-hidden="true">#</a> 上下文管理（with 语句）</h2><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__enter__(self)</code></td><td style="text-align:left;">1. 定义当使用 with 语句时的初始化行为<br>2. <code>__enter__</code> 的返回值被 with 语句的目标或者 as 后的名字绑定</td></tr><tr><td style="text-align:left;"><code>__exit__(self, exc_type, exc_value, traceback)</code></td><td style="text-align:left;">1. 定义当一个代码块被执行或者终止后上下文管理器应该做什么<br>2. 一般被用来处理异常，清除工作或者做一些代码块执行完毕之后的日常工作</td></tr></tbody></table><h2 id="容器类型" tabindex="-1"><a class="header-anchor" href="#容器类型" aria-hidden="true">#</a> 容器类型</h2><table><thead><tr><th style="text-align:left;">魔法方法</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__len__(self)</code></td><td style="text-align:left;">定义当被 len() 调用时的行为（返回容器中元素的个数）</td></tr><tr><td style="text-align:left;"><code>__getitem__(self, key)</code></td><td style="text-align:left;">定义获取容器中指定元素的行为，相当于 self[key]</td></tr><tr><td style="text-align:left;"><code>__setitem__(self, key, value)</code></td><td style="text-align:left;">定义设置容器中指定元素的行为，相当于 self[key] = value</td></tr><tr><td style="text-align:left;"><code>__delitem__(self, key)</code></td><td style="text-align:left;">定义删除容器中指定元素的行为，相当于 del self[key]</td></tr><tr><td style="text-align:left;"><code>__iter__(self)</code></td><td style="text-align:left;">定义当迭代容器中的元素的行为</td></tr><tr><td style="text-align:left;"><code>__reversed__(self)</code></td><td style="text-align:left;">定义当被 reversed() 调用时的行为</td></tr><tr><td style="text-align:left;"><code>__contains__(self, item)</code></td><td style="text-align:left;">定义当使用成员测试运算符（in 或 not in）时的行为</td></tr></tbody></table>',23),a=[r];function o(s,f){return e(),l("div",null,a)}const c=t(_,[["render",o],["__file","python魔法方法.html.vue"]]);export{c as default};
